{
  "integrative": {
    "title": "Integrative Close: Load and Consumption Analysis",
    "objective": "Evaluate the learner's ability to distinguish between instantaneous power measurement and cumulative energy measurement in a practical cost-analysis scenario.",
    "retrievalTextLines": [
      "In professional electrical work, you often provide data to clients regarding both system capacity and running costs. This requires a clear understanding of the difference between measuring the 'rate' of energy use and the 'total' energy consumed over time.",
      "Selecting the wrong instrument here doesn't just give a wrong number; it provides the wrong type of data entirely, making it impossible to calculate costs or verify circuit loading correctly."
    ],
    "questionText": "You are asked to audit a commercial laundry room. You must identify the 'instantaneous power' being drawn by a large dryer to check if the circuit is overloaded, and also record the 'total energy' used by that dryer over a 12-hour shift for billing. Name the two specific instruments required for these measurements and identify which of the two provides a reading of the 'rate' of energy use.",
    "answerGuidance": [
      "Wattmeter (for instantaneous power/rate)",
      "Energy meter or kWh meter (for total energy/consumption)",
      "The Wattmeter is the instrument that measures the rate of energy use."
    ],
    "hint": "Recall which instrument acts like a speedometer (showing the rate right now) and which acts like an odometer (tracking total distance/usage over time)."
  }
}

